# DK FRT.  Fredericia gamle - Taulov
#
let ft = path("d3.dk.frt");

with detail = 4,
     railway = :first :double :removed
{
    with link = "point.dk.Fredericia-gamle", railway = :station {
        track(ft[:fre.a, :fre.ya + 1seg]);
        track(path("d3.dk.fps")[:fre.ya, :fre.ya + 1seg]);
        marker(:left :de.bf, ft[:fre] << 0.5mo << 0.5mt);
        station(:bottom, ft[:fre] << 0.5mo << 0.5mt << 1sh << 0.8dt,
            span(:bold, "Fredericia"),
            hbox(:center:top,
                vbox(:right:top, "FPS: ", "FRT: "),
                vbox(:left:top, "??", "??")
            )
        );
    }

    with link = "line.dk.frt" {
        with layer = -3 track(ft[:fre.ya + 0.99seg, :fre.ak]);
    }
}


